import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './CategorySuggest.css';

const CategorySuggest = ({ currentCategory, onClose }) => {
    const [suggestedName, setSuggestedName] = useState('');
    const [description, setDescription] = useState('');
    const [loading, setLoading] = useState(false);
    const [submitted, setSubmitted] = useState(false);
    const [error, setError] = useState('');
    const [needsLogin, setNeedsLogin] = useState(false);
    const [validating, setValidating] = useState(true);
    const [validToken, setValidToken] = useState(null);

    // Validate token on mount
    useEffect(() => {
        const validateToken = async () => {
            const token = localStorage.getItem('token');
            
            if (!token) {
                setNeedsLogin(true);
                setValidating(false);
                return;
            }
            
            try {
                const response = await fetch('/api/auth/me', {
                    headers: { Authorization: `Bearer ${token}` }
                });
                
                if (response.ok) {
                    setValidToken(token);
                    setNeedsLogin(false);
                } else {
                    // Token is invalid - clear it
                    localStorage.removeItem('token');
                    localStorage.removeItem('user');
                    setNeedsLogin(true);
                }
            } catch (err) {
                setNeedsLogin(true);
            } finally {
                setValidating(false);
            }
        };
        
        validateToken();
    }, []);

    const submitSuggestion = async (name, desc, category) => {
        if (!validToken) {
            setNeedsLogin(true);
            return;
        }

        setLoading(true);
        setError('');
        
        try {
            const response = await axios.post('/api/shop/categories/suggest', {
                parentCategory: category,
                suggestedName: name,
                description: desc
            }, {
                headers: { Authorization: `Bearer ${validToken}` }
            });
            
            if (response.data.success) {
                setSubmitted(true);
                setSuggestedName('');
                setDescription('');
            }
        } catch (err) {
            if (err.response?.status === 401) {
                // Token rejected - clear it
                localStorage.removeItem('token');
                localStorage.removeItem('user');
                setValidToken(null);
                setNeedsLogin(true);
                setError('Your session has expired. Please log in again.');
            } else {
                setError(err.response?.data?.error || 'Failed to submit suggestion');
            }
        } finally {
            setLoading(false);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        
        if (!validToken || needsLogin) {
            setNeedsLogin(true);
            return;
        }
        
        await submitSuggestion(suggestedName, description, currentCategory);
    };

    const handleLogin = () => {
        // Store current location to return after login
        const returnPath = window.location.pathname + window.location.search + window.location.hash;
        sessionStorage.setItem('shopReturnPath', returnPath);
        
        // Clear any stale tokens
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        
        const loginPath = window.location.hostname === 'shop.heavenslive.com' 
            ? '/login'
            : '/shop/login';
        
        window.location.href = loginPath;
    };

    const handleLogoutAndRetry = () => {
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        setValidToken(null);
        setNeedsLogin(true);
        setError('');
    };

    if (validating) {
        return (
            <div className="category-suggest">
                <h4>Suggest a Category</h4>
                <p className="loading-message">Validating session...</p>
            </div>
        );
    }

    if (needsLogin) {
        return (
            <div className="category-suggest">
                <h4>🔐 Login Required</h4>
                <p className="login-message">Please log in to suggest a category.</p>
                <div className="suggest-actions">
                    <button onClick={handleLogin} className="login-btn">
                        Go to Login
                    </button>
                    <button onClick={onClose} className="cancel-btn">
                        Cancel
                    </button>
                </div>
            </div>
        );
    }

    if (submitted) {
        return (
            <div className="category-suggest-success">
                <span>✅ Suggestion submitted for review!</span>
                <button onClick={onClose}>Close</button>
            </div>
        );
    }

    return (
        <div className="category-suggest">
            <h4>Suggest a Category</h4>
            <form onSubmit={handleSubmit}>
                <input
                    type="text"
                    placeholder="Category name"
                    value={suggestedName}
                    onChange={(e) => setSuggestedName(e.target.value)}
                    required
                    minLength={2}
                />
                <textarea
                    placeholder="Description (optional)"
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    rows={3}
                />
                {error && (
                    <div className="error-message">
                        {error}
                        {error.includes('expired') && (
                            <button 
                                onClick={handleLogoutAndRetry}
                                className="retry-link"
                            >
                                Click here to log in again
                            </button>
                        )}
                    </div>
                )}
                <div className="suggest-actions">
                    <button type="submit" disabled={loading}>
                        {loading ? 'Submitting...' : 'Submit for Review'}
                    </button>
                    <button type="button" onClick={onClose} className="cancel-btn">
                        Cancel
                    </button>
                </div>
                <p className="suggest-note">
                    📝 Your suggestion will be reviewed by our admin team.
                </p>
            </form>
        </div>
    );
};

export default CategorySuggest;
